const input = $input.first().json;
const action = input.action || 'list_campaigns';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

async function getGoogleToken() {
  const creds = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&select=cred_key,cred_value',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  const m = {};
  for (const c of creds) m[c.cred_key] = c.cred_value;
  if (!m.access_token || !m.refresh_token) throw new Error('Google OAuth not configured.');
  if (new Date(m.token_expiry || 0) <= new Date(Date.now() + 5 * 60 * 1000)) {
    const resp = await helpers.httpRequest({
      method: 'POST', url: 'https://oauth2.googleapis.com/token',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: 'grant_type=refresh_token&refresh_token=' + encodeURIComponent(m.refresh_token) + '&client_id=' + encodeURIComponent(m.client_id) + '&client_secret=' + encodeURIComponent(m.client_secret)
    });
    if (resp.error) throw new Error('Token refresh failed: ' + resp.error_description);
    const newExpiry = new Date(Date.now() + (resp.expires_in - 60) * 1000).toISOString();
    for (const [key, val] of [['access_token', resp.access_token], ['token_expiry', newExpiry]]) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.' + key, headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: key, cred_value: val }) });
    }
    if (resp.refresh_token) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.refresh_token', headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: 'refresh_token', cred_value: resp.refresh_token }) });
    }
    return resp.access_token;
  }
  return m.access_token;
}

// Load Ads-specific credentials
let adsCreds;
try {
  const rows = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-ads&select=cred_key,cred_value',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  adsCreds = {};
  for (const r of rows) adsCreds[r.cred_key] = r.cred_value;
} catch(e) {
  return [{ json: { error: 'Could not load Google Ads credentials: ' + e.message } }];
}

if (!adsCreds.developer_token) return [{ json: { error: 'Google Ads developer_token not configured. Use add_credential to set it up.' } }];

let accessToken;
try { accessToken = await getGoogleToken(); } catch(e) { return [{ json: { error: e.message } }]; }

const customerId = (adsCreds.customer_id || '').replace(/-/g, '');
if (!customerId) return [{ json: { error: 'No customer_id configured. Use add_credential to set it up.' } }];

const adsHeaders = {
  'Authorization': 'Bearer ' + accessToken,
  'Content-Type': 'application/json',
  'developer-token': adsCreds.developer_token
};
if (adsCreds.login_customer_id) adsHeaders['login-customer-id'] = adsCreds.login_customer_id.replace(/-/g, '');

const ADS_BASE = 'https://googleads.googleapis.com/v23/customers/' + customerId;

async function gaqlQuery(query) {
  return await helpers.httpRequest({
    method: 'POST',
    url: ADS_BASE + '/googleAds:searchStream',
    headers: adsHeaders,
    body: JSON.stringify({ query })
  });
}

// === list_campaigns ===
if (action === 'list_campaigns') {
  let query = 'SELECT campaign.id, campaign.name, campaign.status, campaign.advertising_channel_type, campaign_budget.amount_micros, metrics.impressions, metrics.clicks, metrics.cost_micros FROM campaign';
  if (input.status_filter) {
    query += " WHERE campaign.status = '" + input.status_filter.toUpperCase() + "'";
  } else {
    query += " WHERE campaign.status != 'REMOVED'";
  }
  query += ' ORDER BY campaign.name LIMIT 200';

  try {
    const resp = await gaqlQuery(query);
    const results = resp[0] && resp[0].results ? resp[0].results : [];
    if (results.length === 0) return [{ json: { result: 'No campaigns found.' } }];

    let result = 'Google Ads Campaigns:\n\n';
    for (const r of results) {
      const c = r.campaign;
      const m = r.metrics || {};
      const budget = r.campaignBudget ? (parseInt(r.campaignBudget.amountMicros) / 1000000).toFixed(2) : 'N/A';
      result += '**' + c.name + '** (ID: ' + c.id + ')\n';
      result += 'Status: ' + c.status + ' | Type: ' + c.advertisingChannelType + '\n';
      result += 'Budget: ' + budget + ' | Impressions: ' + (m.impressions || 0) + ' | Clicks: ' + (m.clicks || 0) + '\n';
      if (m.costMicros) result += 'Cost: ' + (parseInt(m.costMicros) / 1000000).toFixed(2) + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch(e) { return [{ json: { error: 'Failed to list campaigns: ' + e.message } }]; }

// === get_campaign_stats ===
} else if (action === 'get_campaign_stats') {
  const campaignId = input.campaign_id;
  const dateFrom = input.date_from;
  const dateTo = input.date_to;
  if (!campaignId || !dateFrom || !dateTo) return [{ json: { error: 'Parameters "campaign_id", "date_from", and "date_to" are required.' } }];

  const query = "SELECT segments.date, metrics.impressions, metrics.clicks, metrics.ctr, metrics.average_cpc, metrics.cost_micros, metrics.conversions, metrics.conversions_value FROM campaign WHERE campaign.id = " + campaignId + " AND segments.date BETWEEN '" + dateFrom + "' AND '" + dateTo + "' ORDER BY segments.date";

  try {
    const resp = await gaqlQuery(query);
    const results = resp[0] && resp[0].results ? resp[0].results : [];
    if (results.length === 0) return [{ json: { result: 'No data found for campaign ' + campaignId + ' in the given date range.' } }];

    let result = 'Campaign ' + campaignId + ' Stats (' + dateFrom + ' to ' + dateTo + '):\n\n';
    result += '| Date | Impressions | Clicks | CTR | Avg CPC | Cost | Conversions |\n';
    result += '| --- | --- | --- | --- | --- | --- | --- |\n';
    for (const r of results) {
      const m = r.metrics || {};
      const date = r.segments ? r.segments.date : '';
      const cost = m.costMicros ? (parseInt(m.costMicros) / 1000000).toFixed(2) : '0';
      const cpc = m.averageCpc ? (parseInt(m.averageCpc) / 1000000).toFixed(2) : '0';
      result += '| ' + date + ' | ' + (m.impressions || 0) + ' | ' + (m.clicks || 0) + ' | ' + (m.ctr ? (m.ctr * 100).toFixed(1) + '%' : '0%') + ' | ' + cpc + ' | ' + cost + ' | ' + (m.conversions || 0) + ' |\n';
    }
    return [{ json: { result } }];
  } catch(e) { return [{ json: { error: 'Campaign stats failed: ' + e.message } }]; }

// === list_ad_groups ===
} else if (action === 'list_ad_groups') {
  const campaignId = input.campaign_id;
  if (!campaignId) return [{ json: { error: 'Parameter "campaign_id" is required.' } }];

  const query = 'SELECT ad_group.id, ad_group.name, ad_group.status, ad_group.type, metrics.impressions, metrics.clicks, metrics.cost_micros FROM ad_group WHERE campaign.id = ' + campaignId + ' ORDER BY ad_group.name LIMIT 50';

  try {
    const resp = await gaqlQuery(query);
    const results = resp[0] && resp[0].results ? resp[0].results : [];
    if (results.length === 0) return [{ json: { result: 'No ad groups found for campaign ' + campaignId + '.' } }];

    let result = 'Ad Groups for Campaign ' + campaignId + ':\n\n';
    for (const r of results) {
      const ag = r.adGroup;
      const m = r.metrics || {};
      result += '**' + ag.name + '** (ID: ' + ag.id + ')\n';
      result += 'Status: ' + ag.status + ' | Type: ' + ag.type + '\n';
      result += 'Impressions: ' + (m.impressions || 0) + ' | Clicks: ' + (m.clicks || 0);
      if (m.costMicros) result += ' | Cost: ' + (parseInt(m.costMicros) / 1000000).toFixed(2);
      result += '\n\n';
    }
    return [{ json: { result } }];
  } catch(e) { return [{ json: { error: 'Failed to list ad groups: ' + e.message } }]; }

// === get_account_stats ===
} else if (action === 'get_account_stats') {
  const dateFrom = input.date_from;
  const dateTo = input.date_to;
  if (!dateFrom || !dateTo) return [{ json: { error: 'Parameters "date_from" and "date_to" are required.' } }];

  const query = "SELECT metrics.impressions, metrics.clicks, metrics.ctr, metrics.cost_micros, metrics.conversions, metrics.conversions_value, metrics.average_cpc FROM customer WHERE segments.date BETWEEN '" + dateFrom + "' AND '" + dateTo + "'";

  try {
    const resp = await gaqlQuery(query);
    const results = resp[0] && resp[0].results ? resp[0].results : [];
    if (results.length === 0) return [{ json: { result: 'No performance data found for the given date range.' } }];

    const m = results[0].metrics || {};
    let result = 'Overall Ad Performance (' + dateFrom + ' to ' + dateTo + '):\n\n';
    result += 'Impressions: ' + (m.impressions || 0) + '\n';
    result += 'Clicks: ' + (m.clicks || 0) + '\n';
    result += 'CTR: ' + (m.ctr ? (m.ctr * 100).toFixed(2) + '%' : 'N/A') + '\n';
    result += 'Avg. CPC: ' + (m.averageCpc ? (parseInt(m.averageCpc) / 1000000).toFixed(2) : 'N/A') + '\n';
    result += 'Total Cost: ' + (m.costMicros ? (parseInt(m.costMicros) / 1000000).toFixed(2) : '0') + '\n';
    result += 'Conversions: ' + (m.conversions || 0) + '\n';
    result += 'Conversion Value: ' + (m.conversionsValue || 0) + '\n';
    return [{ json: { result } }];
  } catch(e) { return [{ json: { error: 'Ad performance query failed: ' + e.message } }]; }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: list_campaigns, get_campaign_stats, list_ad_groups, get_account_stats.' } }];
}
